#include <iostream>
#include <stack>

using namespace std;

class QueueFromStacks
{
private:
    stack<int> in;
    stack<int> out;

    void transferIfNeeded()
    {
        if (out.empty())
        {
            while (!in.empty())
            {
                out.push(in.top());
                in.pop();
            }
        }
    }

public:
    void push(int value)
    {
        in.push(value);
    }

    int pop()
    {
        transferIfNeeded();
        int front = out.top();
        out.pop();
        return front;
    }
};

int main()
{
    QueueFromStacks q;
    q.push(1);
    q.push(2);
    q.push(3);

    cout << q.pop() << " ";
    cout << q.pop() << " ";
    cout << q.pop() << " ";

    return 0;
}

