#include <iostream>
#include <vector>

using namespace std;

class RecentCounter {
public:
    vector<int> pings;

    int ping(int t)
    {
        pings.push_back(t);
        int count = 0;
        for (int p : pings)
        {
            if (p >= t - 3000) count++;
        }
        return count;
    }
};

int main()
{
    RecentCounter rc;
    cout << rc.ping(1) << " " << rc.ping(100) << " " << rc.ping(3001) << " " << rc.ping(3002) << endl;

    return 0;
}

#include <iostream>
#include <queue>

using namespace std;

class RecentCounter {
public:
    queue<int> requests;

    int ping(int t)
    {
        requests.push(t);

        while (requests.front() < t - 3000)
        {
            requests.pop();
        }

        return requests.size();
    }
};

int main()
{
    RecentCounter rc;
    cout << rc.ping(1) << " " << rc.ping(100) << " " << rc.ping(3001) << " " << rc.ping(3002) << endl;

    return 0;
}

